#include<bits/stdc++.h>
using namespace std;
int gcd(int a, int b) {
    while (b) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    int n;
    cin >> n;

    int a[10001];
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }
    int cnt= a[0];
    for (int i = 1; i < n; ++i) {
        cnt = gcd(cnt, a[i]);
    }
    if (cnt != 1) {
        cout << -1 << endl;
        return 0;
    }
    int size = *max_element(a, a+n);
    int up = size * size;

    int dp[up + 1]={0};
    dp[0] = 1;
    int cnt2 = 0;
    for (int x = 1; x <= up; ++x) {
        bool pos = false;
        for (int i=0;i<n;i++) {
            if (x >= a[i] && dp[x - a[i]]) {
                pos = true;
                break;
            }
        }
        if (!pos) {
            cnt++;
        }
        dp[x] = pos;
    }

    cout << cnt-1 << endl;

    return 0;
}
